{
  "resources": [
    {
      "name": "Hope Rescue Mission – Safe Haven Men’s Shelter",
      "addresses": [
        "645 N 6th St, Reading, PA 19601"
      ],
      "phones": [
        "(610) 375-4224"
      ],
      "emails": [],
      "website": "https://www.hopeforreading.org",
      "description": "Hope Rescue Mission’s Safe Haven program is an emergency shelter for adult men experiencing homelessness in Reading. The shelter provides nightly beds plus access to showers, restrooms, laundry, meals, and Wi‑Fi in a dormitory-style setting. Safe Haven typically operates daily in the late afternoon through morning hours and can accommodate around 85 men. Additional Code Blue beds may be available in cold weather. This is a male-only program; men must complete intake and follow shelter rules. Contact or visit in the afternoon/early evening for current bed availability and intake requirements.",
      "justification": "Client needs showers and restrooms in Reading, PA. Hope Rescue Mission’s Safe Haven specifically lists showers and operates as a men’s emergency shelter within the city limits, making it an appropriate option for adult male clients needing hygiene facilities.",
      "referral_type": "external"
    },
    {
      "name": "LightHouse Women’s & Children’s Center (Hope Rescue Mission)",
      "addresses": [
        "715 N 6th St, Reading, PA 19601"
      ],
      "phones": [
        "(610) 484-4495"
      ],
      "emails": [],
      "website": "https://www.hopeforreading.org/about-lighthouse",
      "description": "LightHouse is a women’s and children’s center operated by Hope Rescue Mission in Reading. The 43-room facility offers emergency and transitional housing for single women and mothers with children. Each room has access to a private bathroom and shower, along with a microwave and small refrigerator/freezer. Stays range from 1–3 nights for emergency shelter to up to six months for transitional housing. Several rooms are ADA-compliant. This program is limited to women and their children; uncaged pets are not allowed in transitional housing. Call for current intake process, availability, and any documentation requirements.",
      "justification": "Client needs access to showers and restrooms. LightHouse provides private bathrooms and showers as part of its emergency and transitional housing for women and children, and it is located in Reading, PA, close to the client’s stated location.",
      "referral_type": "external"
    },
    {
      "name": "Goodwill Keystone Area – Goodwill Store & Donation Center (Reading – Lancaster Ave)",
      "addresses": [
        "602 E Lancaster Ave, Reading, PA 19607"
      ],
      "phones": [
        "(610) 777-5250"
      ],
      "emails": [
        "stores@yourgoodwill.org"
      ],
      "website": "https://www.yourgoodwill.org",
      "description": "This is a Goodwill Keystone Area retail store and donation center serving the Reading region. It does not advertise public shower or restroom facilities for community use. However, as the local Goodwill presence, store staff may be able to confirm whether any Goodwill-operated programs or nearby partner agencies currently offer hygiene or shower access and can provide up-to-date contact information or referrals. Call or visit during store hours to inquire about any Goodwill programs or collaborations that may support individuals experiencing homelessness.",
      "justification": "The case manager asked specifically about Goodwill locations with showers in Reading. Publicly available information for this Goodwill store does not indicate showers or public restrooms for client use, but it is the closest Goodwill Keystone Area site; staff may offer guidance or referrals. It should not be presented as a shower resource itself.",
      "referral_type": "goodwill"
    }
  ]
}

{
  "resources": [
    {
      "name": "United Way of Berks County – PA 211 Information and Referral",
      "addresses": [
        "631 Penn Street, Reading, PA 19601"
      ],
      "phones": [
        "211",
        "610-685-4550"
      ],
      "emails": [],
      "website": "https://www.uwberks.org/call-211/",
      "description": "United Way of Berks County operates PA 211 for Berks residents, a free 24/7 information and referral line that connects people to basic-needs assistance. Trained specialists assess needs and refer callers to local resources for food pantries and meals, emergency shelter and housing help (including rent and utility assistance), transportation, health and mental health services, elder care, childcare, and more. Help is available in multiple languages. You can dial 211, text your ZIP code to 898211, or search online for services. This is the primary United Way–run access point for basic-needs help in and around Reading.",
      "justification": "Client asked specifically what United Way of Berks County offers for basic-needs assistance near Reading, PA. United Way’s core basic-needs support is delivered through the PA 211 information and referral service, which is listed by United Way of Berks County and local school district guides as the main entry point for food, housing, utilities, and other emergency help for Berks County residents. The office is located in downtown Reading and serves all city residents.",
      "referral_type": "government"
    },
    {
      "name": "United Way of Berks County – Safety Net Services (Funded Basic Needs Programs)",
      "addresses": [
        "631 Penn Street, Reading, PA 19601"
      ],
      "phones": [
        "610-685-4550"
      ],
      "emails": [],
      "website": "https://www.uwberks.org/safety-net-services/",
      "description": "Through its Safety Net Services focus area, United Way of Berks County funds a network of local agencies that provide basic-needs assistance to Berks residents. These include emergency shelter (Opportunity House), food access and soup kitchen services (New Journey Community Outreach, Helping Harvest), rent and utility assistance to prevent homelessness (Berks Coalition to End Homelessness, Salvation Army Reading Corps and Service Extension Unit), domestic violence and sexual assault crisis shelter (Safe Berks), legal aid for low-income clients to secure basic needs (MidPenn Legal Services), and other crisis and emergency aid. Residents typically access these programs either by contacting the partner agencies directly or by calling 211 for referrals.",
      "justification": "Client wants to know what United Way of Berks County offers for basic-needs assistance. United Way itself does not usually provide direct basic-needs services but funds Safety Net Services through partner agencies located in Reading and throughout Berks County. The Safety Net Services page describes these funded programs and confirms they cover basic needs such as shelter, food, utilities, and crisis support for Berks County residents, including those in Reading.",
      "referral_type": "external"
    },
    {
      "name": "United Way of Berks County – Guide for Help (Basic Needs Resource Guide)",
      "addresses": [
        "631 Penn Street, Reading, PA 19601"
      ],
      "phones": [
        "211",
        "610-685-4550"
      ],
      "emails": [],
      "website": "https://www.uwberks.org/guide-for-help/",
      "description": "United Way of Berks County publishes a \"Guide for Help\" for individuals and families facing income gaps, delayed benefits, or job instability. The guide walks residents through assessing their situation and prioritizing essential bills, and it compiles local contacts for food, housing, utility assistance, mental health, and other basic-needs services. It highlights PA 211 as the one-stop information source, and includes local providers such as Helping Harvest, Centro Hispano, and other community organizations. The guide is available in English and Spanish as a downloadable PDF and is tailored specifically to Berks County residents, including those in Reading.",
      "justification": "Because the client asked what United Way of Berks County offers for basic-needs assistance, this official United Way guide is directly relevant. It is created and maintained by United Way of Berks County as a practical tool to connect Berks County residents to food, housing, utilities, and other emergency resources, and it centers on local options accessible from Reading.",
      "referral_type": "external"
    }
  ]
}

{
  "resources": [
    {
      "name": "Berks Community Action Program (BCAP) – Budget Counseling, Rental & Utility Assistance",
      "addresses": [
        "645 Penn Street, 3rd Floor, PO Box 22, Reading, PA 19601"
      ],
      "phones": [
        "610-376-6571",
        "610-375-7866 x41"
      ],
      "emails": [
        "info@bcapberks.org"
      ],
      "website": "https://bcapberks.org/budget-counseling/",
      "description": "BCAP’s Budget Counseling Center provides rental and utilities assistance for income-eligible Berks County residents, along with budget counseling, homeownership counseling, delinquency and mortgage assistance, and credit repair. For rental and/or utility help, clients must meet federal, state, and local poverty guidelines; BCAP staff screen for eligibility and can advise on documentation needed. Services are designed to stabilize housing and prevent loss of utilities while improving long‑term financial management. Appointments are required; applicants are encouraged to complete BCAP’s rental/utility assistance forms before meeting with a counselor.",
      "justification": "Client is in Reading, PA and needs help with utility bills and housing. BCAP is the primary community action agency for Berks County and explicitly offers rental and utilities assistance tied to budget counseling for low‑income residents, with clear eligibility based on poverty guidelines. The Reading office is located in downtown Reading, within the city specified by the case manager, making it highly accessible for the client.",
      "referral_type": "external"
    },
    {
      "name": "Berks Community Action Program (BCAP) – Homeless Assistance Program",
      "addresses": [
        "645 Penn Street, 3rd Floor, PO Box 22, Reading, PA 19601"
      ],
      "phones": [
        "610-376-6571"
      ],
      "emails": [
        "info@bcapberks.org"
      ],
      "website": "https://bcapberks.org/homeless-assistance/",
      "description": "BCAP’s Homeless Assistance Program provides rental-related payments directly to landlords for eligible households who are homeless or at immediate risk of homelessness due to eviction or similar circumstances. Assistance may cover security deposits, first month’s rent, or both, after the client meets income and other eligibility criteria and can demonstrate ability to maintain ongoing rent. Applicants complete a pre‑screening application prior to an appointment. This program is targeted to Berks County residents facing housing crises and is designed to prevent or shorten episodes of homelessness.",
      "justification": "Client has housing instability concerns in Reading, PA. BCAP’s Homeless Assistance Program specifically addresses rental support to avoid eviction and homelessness for Berks County residents and is administered at the same central Reading office, minimizing travel. It is appropriate for clients either currently homeless or facing eviction who can sustain rent going forward.",
      "referral_type": "external"
    },
    {
      "name": "Berks Community Action Program (BCAP) – Mortgage Diversion / Mortgage Assistance",
      "addresses": [
        "645 Penn Street, 3rd Floor, PO Box 22, Reading, PA 19601"
      ],
      "phones": [
        "610-376-6571"
      ],
      "emails": [
        "info@bcapberks.org"
      ],
      "website": "https://bcapberks.org/mortgage-assistant/",
      "description": "BCAP’s Mortgage Diversion Program supports homeowners who are behind on their mortgage and have received a sheriff’s (Urgent) Notice. HUD‑certified housing counselors work with the mortgage company at no cost to the homeowner to explore options that may help them stay in their home while they regain financial stability. Clients are instructed to contact one of the listed counseling agencies within 10 days of receiving the notice; BCAP is one of these agencies and provides forms and checklists to prepare for appointments. This program is best suited for low‑ to moderate‑income homeowners in Berks County at risk of foreclosure rather than renters.",
      "justification": "If the client is a homeowner in or near Reading, PA who has fallen behind on mortgage payments, this BCAP program is directly relevant to preventing loss of housing. It is administered from the same central Reading office and is tailored to low‑income households needing structured foreclosure prevention help.",
      "referral_type": "external"
    }
  ]
}

