{
  "resources": [
    {
      "name": "Texas Workforce Solutions – Vocational Rehabilitation Services (Hearing Aids for Employment)",
      "addresses": [
        "North Austin Workforce Solutions Office, 9001 N IH 35, Suite 110, Austin, TX 78753",
        "East Austin Workforce Solutions Office, 3401 Webberville Rd, Building 1000, Austin, TX 78702"
      ],
      "phones": [
        "512-936-6400"
      ],
      "emails": [],
      "website": "https://www.twc.texas.gov/services/vocational-rehabilitation-services",
      "description": "State vocational rehabilitation (VR) program that can purchase hearing aids and related assistive devices for eligible people with hearing loss when needed for work or vocational training. VR serves adults and youth with disabilities whose condition makes it hard to get, keep, or advance in a job. Income does not affect basic eligibility, and SSI/SSDI recipients are generally not required to share costs. Services can include audiology evaluations, hearing aids, earmolds, assistive listening devices, job placement, and other supports tied to employment goals.",
      "justification": "Best fit if the client has a documented or suspected hearing loss that affects employment or training. TWC-VR policy specifically authorizes paying for hearing aids for deaf or hard-of-hearing customers when recommended by an audiologist and needed for work or training. Client must be able to pursue work or education; no strict income cap, which helps low-income adults in Austin.",
      "referral_type": "government"
    },
    {
      "name": "Starkey Cares – Hear Now Program (National Low-Cost Hearing Aids)",
      "addresses": [],
      "phones": [
        "855-686-2202"
      ],
      "emails": [
        "starkeycares@starkey.com"
      ],
      "website": "https://www.starkey.com/starkeycares",
      "description": "Manufacturer-based assistance program that provides Starkey hearing aids at significantly reduced cost to low-income individuals nationwide through partner clinics. Applicants must meet income guidelines and work with a participating hearing provider who agrees to fit the aids and provide several follow-up visits at no charge. Clients typically pay only a modest application fee rather than full hearing-aid cost.",
      "justification": "Appropriate if the client is low-income, uninsured or underinsured, and does not have another payer for hearing aids. Can be combined with a local Austin audiology clinic that participates in Starkey Cares. Good option when commercial insurance or Medicaid does not cover hearing aids for adults.",
      "referral_type": "external"
    },
    {
      "name": "Local Lions Clubs – Hearing Aid Assistance (Austin Area)",
      "addresses": [],
      "phones": [
        "512-936-3270"
      ],
      "emails": [],
      "website": "https://www.lionsclubs.org",
      "description": "Lions Clubs may offer help with eye exams, eyeglasses, and sometimes hearing aids for low-income community members. Assistance is handled locally by each club and depends on available funds. Clients generally complete an application and may need proof of income and a recent hearing evaluation or quote for hearing aids. Case managers or clients can use the Lions Club \"Find a Club\" tool to locate Austin-area clubs and email them directly to request help.",
      "justification": "Relevant because Lions International directs people needing help with hearing aids to apply through their local Lions Club, which may provide partial or full funding depending on resources. This is a common charitable option for adults in Austin who cannot afford hearing aids.",
      "referral_type": "external"
    },
    {
      "name": "Central Health – Medical Access Program (MAP) (Travis County)",
      "addresses": [
        "Central Health Administrative Offices, 1111 E. Cesar Chavez St., Austin, TX 78702"
      ],
      "phones": [
        "512-978-8130"
      ],
      "emails": [],
      "website": "https://www.centralhealth.net/map/",
      "description": "County medical assistance program for low-income Travis County residents. MAP and MAP Basic are not insurance but can cover primary and specialty care, diagnostics, and prescriptions through a network of clinics. While MAP does not advertise direct payment for hearing aids, enrollment can connect clients to primary care providers and specialists (including audiology or ENT) and reduce or eliminate visit costs. Having MAP can also help when applying to manufacturer or charity programs that require recent hearing evaluations or physician documentation.",
      "justification": "Useful foundational resource for low-income clients in Austin who lack insurance. Even if MAP does not pay directly for hearing aids, it can cover the audiology/ENT visits and testing needed to qualify for Starkey Cares, Lions Club assistance, or VR services.",
      "referral_type": "government"
    },
    {
      "name": "People’s Community Clinic (Primary Care & Referrals, Austin)",
      "addresses": [
        "1101 Camino La Costa, Austin, TX 78752"
      ],
      "phones": [
        "512-478-4939"
      ],
      "emails": [],
      "website": "https://www.austinpcc.org/",
      "description": "Nonprofit community health center providing low-cost primary care, chronic disease management, women’s health, pediatrics, and behavioral health regardless of insurance or immigration status. Uses sliding-scale fees based on income and accepts MAP, Medicaid, and many insurance plans. While they do not directly advertise free hearing aids, they can evaluate basic hearing concerns, provide referrals to audiology or ENT, and document medical need for hearing aids, which is often required for assistance programs.",
      "justification": "Good starting point if the client has no regular doctor or needs a low-cost evaluation and referral for hearing loss. Located in Austin and accustomed to serving low-income and uninsured patients, which aligns with the client’s financial situation.",
      "referral_type": "external"
    }
  ]
}

