{
  "resources": [
    {
      "name": "City of Austin First Workers' Day Labor Program",
      "addresses": [
        "700 East 7th Street, Austin, TX 78701"
      ],
      "phones": [
        "512-972-4100"
      ],
      "emails": [],
      "website": "https://www.austintexas.gov/department/day-labor",
      "description": "The City of Austin’s First Workers' Day Labor Program is a city-run day labor center that connects people seeking immediate, same-day work with employers who need temporary labor. Typical jobs include construction cleanup, moving, landscaping, painting, roofing, carpentry, plumbing assistance, welding, demolition, and other general labor. Workers are usually paid in cash by the employer at the end of the day. The program also offers access to case management referrals, community health nursing, and referrals for food and rent/utility assistance. Re-entry supports include a four-week Moral Reconation Therapy (MRT) series focused on anger management, cognitive skills, and job readiness. The program primarily serves people experiencing homelessness, migrant workers, and individuals returning from incarceration, but is open to anyone seeking day labor work.",
      "justification": "This is the City of Austin’s official day labor program and the primary same-day work option in Travis County. It offers exactly what the client is requesting: immediate, cash-paid day labor jobs. From Austin ZIP code 78704, this downtown site (700 E 7th St, 78701) is roughly 3–5 miles away depending on the starting point in 78704 and is reachable via public transit or car. The program is government-operated, low-barrier, and specifically designed for individuals with unstable housing, migrant workers, and re-entry clients.",
      "referral_type": "government"
    }
  ]
}

{
